sql:
SELECT average_mpg
FROM fuel_efficiency_reports
WHERE vehicle_id = '0';

external_knowledge:
- 'recently' refers to the last month; 
- 'top-performing' and 'most fuel-efficient' refer to the vehicles with the shortest lap times and the highest average miles per gallon, respectively; 
- 'crème de la crème' refers to the best of the best, in this case, the top 3 vehicles per make and model; 
- 'impressive stats' include lap time and top speed; 
- 'how much they guzzle' refers to the average miles per gallon and cost per mile; 
- 'price tag of their maintenance' refers to the total maintenance cost.

sql:
SELECT driving_conditions, AVG(average_mpg) AS avg_mpg
FROM fuel_efficiency_reports
GROUP BY driving_conditions;

SELECT v.vehicle_id, f.average_mpg
FROM vehicles v
INNER JOIN fuel_efficiency_reports f ON v.vehicle_id = f.vehicle_id
WHERE v.cylinders > 4 AND f.average_mpg > (
    SELECT AVG(average_mpg) FROM fuel_efficiency_reports
);

SELECT average_mpg, cost_per_mile
FROM fuel_efficiency_reports
ORDER BY average_mpg DESC;
